import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface RecentBuild {
  buildId: string;
  status: string;
  duration: string;
}

interface PipelineData {
  recentBuilds: RecentBuild[];
  successRate: number;
  avgDeployTime: string;
}

export default function Widget() {
  const pipelineData = response.data as PipelineData;
  const successRateData = [
    { status: 'Success', value: pipelineData.successRate },
    { status: 'Failure', value: 100 - pipelineData.successRate },
  ];

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#1E1E1E' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FFC107' }}>
              Build Monitor
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Average Deploy Time: {pipelineData.avgDeployTime}
            </Typography>
          </Box>

          <PieChart
            height={120}
            data={successRateData}
            series={[
              {
                innerRadius: 30,
                outerRadius: 60,
                color: (d: any) => (d.status === 'Success' ? '#0D47A1' : '#FFC107'),
                label: (d: any) => `${d.value.toFixed(1)}%`,
              },
            ]}
            sx={{
              '& .MuiChartsPieLabel-root': {
                fill: '#FFFFFF',
                fontSize: 12,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {pipelineData.recentBuilds.map((build) => (
              <Chip
                key={build.buildId}
                label={`${build.buildId} (${build.status})`}
                sx={{
                  bgcolor: build.status === 'Success' ? '#0D47A1' : '#FFC107',
                  color: '#FFFFFF',
                  fontSize: '10px',
                  px: 1,
                }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
